import type { Candidate } from "./paragraph-data";

interface ProbabilityPopoverProps {
  candidates: Candidate[];
}

export function ProbabilityPopover({ candidates }: ProbabilityPopoverProps) {
  return (
    <span
      aria-hidden="true"
      className="-translate-x-1/2 sm:-top-1 pointer-events-none absolute top-full left-1/2 z-10 mt-2 block w-[16rem] animate-in rounded-md border border-border bg-card/95 p-3 font-mono text-foreground/85 text-xs shadow-lg backdrop-blur-sm duration-200 fade-in zoom-in-95 sm:bottom-full sm:mt-0 sm:mb-2 sm:w-[18rem]"
    >
      <span className="block space-y-1">
        {candidates.map((candidate) => (
          <span className="block" key={candidate.text}>
            <span className="flex items-center gap-2">
              <span
                className={cn(
                  "min-w-0 flex-1 truncate",
                  candidate.chosen
                    ? "font-semibold text-foreground"
