  if (reducedMotion) {
    return (
      <p
        aria-live="polite"
        className="text-foreground/65 text-xs sm:text-sm"
      >
        <span aria-hidden="true" className="mr-2 select-none">
          {"↳"}
        </span>
        grounded in {RETRIEVED_DOCS.length} docs.
      </p>
    );
