  const docsTotal =
    RETRIEVAL_START_MS +
    RETRIEVED_DOCS.length * RETRIEVAL_DOC_STAGGER_MS +
    RETRIEVAL_HOLD_MS;

  return (
    <div
      aria-live="polite"
      className="relative min-h-[1.5rem] text-foreground/65 text-xs sm:text-sm"
    >
      <span className="sr-only">Grounded in {RETRIEVED_DOCS.length} documents.</span>

      <div aria-hidden="true">
        <ul className="space-y-0.5">
          {RETRIEVED_DOCS.map((doc, index) => (
            <li
              className="opacity-0"
              key={doc}
              style={{
                animation: `ht-doc-flash ${docsTotal - RETRIEVAL_START_MS}ms ease-in-out ${
                  RETRIEVAL_START_MS + index * RETRIEVAL_DOC_STAGGER_MS
                }ms forwards`,
              }}
            >
              <span className="mr-2 select-none text-foreground/40">·</span>
              <span className="font-mono">{doc}</span>
            </li>
          ))}
        </ul>
        <p
          className="absolute inset-0 opacity-0"
          style={{
            animation: `ht-grounded-final 400ms ease-out ${docsTotal}ms forwards`,
          }}
        >
          <span className="mr-2 select-none">{"↳"}</span>
          grounded in {RETRIEVED_DOCS.length} docs.
        </p>
      </div>
    </div>
  );
}

