"use client";

import { Button } from "@repo/design-system/components/ui/button";
import { useCallback, useEffect, useState } from "react";
import { MetaAside } from "../../components/meta-aside";
import { GroundedParagraph } from "./grounded-paragraph";
import { HINGE_TO_BEAT_3, HINGE_TO_REALITY } from "./paragraph-data";
import { OwnedAnswer } from "./owned-answer";
import { PromptInput } from "./prompt-input";
import { StreamingParagraph } from "./streaming-paragraph";

const BEAT_2_REVEAL_DELAY_MS = 800;

function useReducedMotion() {
  const [reduced, setReduced] = useState(false);
  useEffect(() => {
    const query = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReduced(query.matches);
    const handler = (event: MediaQueryListEvent) => setReduced(event.matches);
    query.addEventListener("change", handler);
    return () => query.removeEventListener("change", handler);
  }, []);
  return reduced;
}

export function Plausibility() {
  const reducedMotion = useReducedMotion();
  const [streamPlays, setStreamPlays] = useState(0);
  const [beat1Complete, setBeat1Complete] = useState(false);
  const [beat2Visible, setBeat2Visible] = useState(false);
  const [beat3Visible, setBeat3Visible] = useState(false);

  const handleStreamComplete = useCallback(() => {
    setBeat1Complete(true);
  }, []);

  useEffect(() => {
    if (!beat1Complete || beat2Visible) {
      return;
    }
    const id = window.setTimeout(
      () => setBeat2Visible(true),
      BEAT_2_REVEAL_DELAY_MS
    );
    return () => window.clearTimeout(id);
  }, [beat1Complete, beat2Visible]);

  const playPressed = streamPlays > 0;

  return (
    <div className="rounded-2xl border border-border bg-card/40 p-5 shadow-sm sm:p-8">
      <PromptInput amended={beat2Visible} reducedMotion={reducedMotion} />

      <div className="mt-6 min-h-[10rem]">
        {playPressed ? (
          <StreamingParagraph
            enabled={true}
            key={streamPlays}
            onComplete={handleStreamComplete}
            reducedMotion={reducedMotion}
          />
        ) : (
          <p className="font-display text-foreground/30 text-lg leading-8">
            {/* paragraph empty until play */}
          </p>
        )}
      </div>

      <div className="mt-6 flex flex-col items-end gap-3">
        {!playPressed && (
          <MetaAside className="text-right">
            This will take nine seconds. Every other AI demo lies about that.
          </MetaAside>
        )}
        {!beat1Complete && (
          <Button
            aria-label="Play the LLM generation animation"
            onClick={() => {
              setStreamPlays((n) => n + 1);
              setBeat1Complete(false);
            }}
            variant="outline"
          >
            {playPressed ? "Generating…" : "▶ Watch how it generates"}
          </Button>
        )}
        {beat1Complete && (
          <Button
            aria-label="Replay the LLM generation animation"
            onClick={() => {
              setStreamPlays((n) => n + 1);
              setBeat1Complete(false);
            }}
            variant="ghost"
          >
            ↻ Replay
          </Button>
        )}
      </div>

      {beat2Visible && (
        <div className="mt-12 border-border/60 border-t pt-8">
          <GroundedParagraph />
          {!beat3Visible && (
            <div className="mt-8 flex flex-col items-start gap-4">
              <MetaAside variant="block" className="max-w-prose">
                {HINGE_TO_BEAT_3}
              </MetaAside>
              <Button onClick={() => setBeat3Visible(true)} variant="outline">
                Show what was actually wrong.
              </Button>
            </div>
          )}
        </div>
      )}

      {beat3Visible && (
        <div className="mt-8 border-border/60 border-t pt-8">
          <OwnedAnswer reducedMotion={reducedMotion} />
          <MetaAside variant="block" className="mt-8 max-w-prose">
            {HINGE_TO_REALITY}
          </MetaAside>
        </div>
      )}
    </div>
  );
}

