import { useEffect, useRef, useState } from "react";
import type { PauseId, Token } from "./paragraph-data";

const COMMON_TOKEN_MS = 50;
const PUNCTUATION_TOKEN_MS = 150;
const PAUSE_HOLD_MS = 600;
const PUNCTUATION = new Set([".", ",", "!", "?", ";", ":"]);

function tokenDelay(token: Token | undefined) {
  if (!token) {
    return COMMON_TOKEN_MS;
  }
  return PUNCTUATION.has(token.text.trim())
    ? PUNCTUATION_TOKEN_MS
    : COMMON_TOKEN_MS;
}

function buildRevealSchedule(tokens: Token[]) {
  const revealAt: number[] = [];
  let elapsed = 0;
  for (const token of tokens) {
    elapsed += tokenDelay(token);
    revealAt.push(elapsed);
    if (token.pause) {
      elapsed += PAUSE_HOLD_MS;
    }
  }
  return revealAt;
}

type UseStreamingOptions = {
  tokens: Token[];
  enabled: boolean;
  reducedMotion?: boolean;
  onComplete?: () => void;
};

type UseStreamingReturn = {
  visibleCount: number;
  activePause: PauseId | null;
  isComplete: boolean;
};

export function useStreaming({
  tokens,
  enabled,
  reducedMotion = false,
  onComplete,
}: UseStreamingOptions): UseStreamingReturn {
  const [visibleCount, setVisibleCount] = useState(0);
  const [activePause, setActivePause] = useState<PauseId | null>(null);
  const [isComplete, setIsComplete] = useState(false);

  const onCompleteRef = useRef(onComplete);
  onCompleteRef.current = onComplete;

  useEffect(() => {
    if (!enabled) {
      setVisibleCount(0);
      setActivePause(null);
      setIsComplete(false);
      return;
    }

    if (reducedMotion) {
      setVisibleCount(tokens.length);
      setActivePause(null);
      setIsComplete(true);
      onCompleteRef.current?.();
      return;
    }

    const revealAt = buildRevealSchedule(tokens);
    const totalDuration = revealAt[revealAt.length - 1] ?? 0;

    let cancelled = false;
    let rafId = 0;
    let startTime: number | null = null;
    let lastCount = -1;
    let lastPause: PauseId | null | undefined;
    let completionFired = false;

    const tick = (timestamp: number) => {
      if (cancelled) {
        return;
      }
      if (startTime === null) {
        startTime = timestamp;
      }
      const elapsed = timestamp - startTime;

      let count = 0;
      while (count < revealAt.length && elapsed >= revealAt[count]) {
        count += 1;
      }

      let currentPause: PauseId | null = null;
      if (count > 0) {
        const last = tokens[count - 1];
        if (last.pause) {
          const pauseStart = revealAt[count - 1];
          if (elapsed < pauseStart + PAUSE_HOLD_MS) {
            currentPause = last.pause;
          }
        }
      }

      if (count !== lastCount) {
        setVisibleCount(count);
        lastCount = count;
      }
      if (currentPause !== lastPause) {
        setActivePause(currentPause);
        lastPause = currentPause;
      }

      if (count >= tokens.length && elapsed >= totalDuration) {
        if (!completionFired) {
          setIsComplete(true);
          onCompleteRef.current?.();
          completionFired = true;
        }
        return;
      }

      rafId = requestAnimationFrame(tick);
    };

    rafId = requestAnimationFrame(tick);

    return () => {
      cancelled = true;
      cancelAnimationFrame(rafId);
    };
  }, [enabled, reducedMotion, tokens]);

  return { visibleCount, activePause, isComplete };
}

