"use client";

import { useEffect } from "react";
import { OWNED_ANSWER } from "./paragraph-data";

interface OwnedAnswerProps {
  reducedMotion: boolean;
}

export function OwnedAnswer({ reducedMotion }: OwnedAnswerProps) {
  useEffect(() => {
    if (reducedMotion) {
      return;
    }
    const profiling = document.querySelector<HTMLElement>(
      "[data-profiling-sentence]"
    );
    if (!profiling) {
      return;
    }
    profiling.classList.add("ht-profiling-pulse");
    const id = window.setTimeout(() => {
      profiling.classList.remove("ht-profiling-pulse");
    }, 700);
    return () => {
      window.clearTimeout(id);
      profiling.classList.remove("ht-profiling-pulse");
    };
  }, [reducedMotion]);

  return (
    <div className="relative pt-10">
      {!reducedMotion && (
        <svg
          aria-hidden="true"
          className="absolute top-0 left-1/2 -translate-x-1/2 text-foreground/20"
          fill="none"
          height="32"
          viewBox="0 0 2 32"
          width="2"
        >
          <line
            stroke="currentColor"
            strokeDasharray="32"
            strokeDashoffset="32"
            strokeWidth="1"
            style={{ animation: "ht-line-draw 600ms ease-out forwards" }}
            x1="1"
            x2="1"
            y1="0"
            y2="32"
          />
        </svg>
      )}

      <blockquote className="font-display text-base text-foreground/55 italic leading-7">
        {OWNED_ANSWER.quotedFromGrounded.text}
        <span className="line-through decoration-2 decoration-red-500/70">
          <span className="sr-only">struck through: </span>
          {OWNED_ANSWER.quotedFromGrounded.strikeThroughClause}
        </span>
      </blockquote>

      <p className="mt-6 font-display font-semibold text-foreground text-xl leading-8">
        {OWNED_ANSWER.callout}
      </p>

      <p className="mt-6 font-display text-foreground/85 text-lg leading-8">
        {OWNED_ANSWER.diagnosis.split(/(`[^`]+`)/g).map((chunk, index) => {
          if (chunk.startsWith("`") && chunk.endsWith("`")) {
            return (
              <code
                className="rounded bg-foreground/[0.06] px-1 py-0.5 font-mono text-[0.95em] text-foreground/90"
                key={`${index}-code`}
              >
                {chunk.slice(1, -1)}
              </code>
            );
          }
          return <span key={`${index}-text`}>{chunk}</span>;
        })}
      </p>

      <pre className="mt-6 overflow-x-auto rounded-md border border-border/60 bg-foreground/[0.03] p-4 font-mono text-sm leading-6">
        <code>
          {OWNED_ANSWER.diff.removed.map((line) => (
            <div
              className="text-red-600/85 dark:text-red-400/90"
              key={`r-${line}`}
            >
              <span aria-hidden="true" className="select-none">
                {"- "}
              </span>
              {line}
            </div>
          ))}
          {OWNED_ANSWER.diff.added.map((line) => (
            <div
              className="text-emerald-700/90 dark:text-emerald-400/95"
              key={`a-${line}`}
            >
              <span aria-hidden="true" className="select-none">
                {"+ "}
              </span>
              {line}
            </div>
          ))}
        </code>
      </pre>

      <style>{`
        @keyframes ht-line-draw {
          to { stroke-dashoffset: 0; }
        }
        @keyframes ht-profiling-pulse-kf {
          0% { background-color: transparent; }
          40% { background-color: var(--color-ht-cyan-200); }
          100% { background-color: transparent; }
        }
        .ht-profiling-pulse {
          animation: ht-profiling-pulse-kf 700ms ease-out;
          border-radius: 0.25rem;
          padding: 0 0.125rem;
          margin: 0 -0.125rem;
        }
      `}</style>
    </div>
  );
}

