"use client";

import { Switch } from "@repo/design-system/components/ui/switch";
import { cn } from "@repo/design-system/lib/utils";

interface ToggleRowProps {
  caption: string;
  checked: boolean;
  id: string;
  label: string;
  offLabel: string;
  onCheckedChange: (next: boolean) => void;
  onLabel: string;
}

function ToggleRow({
  caption,
  checked,
  id,
  label,
  offLabel,
  onCheckedChange,
  onLabel,
}: ToggleRowProps) {
  return (
    <div className="flex flex-col gap-1.5">
      <label className="font-medium font-mono text-[0.7rem] text-foreground/60 uppercase tracking-[0.2em]" htmlFor={id}>
        {label}
      </label>
      <div className="flex items-center gap-3">
        <span
          className={cn(
            "font-mono text-sm transition-colors",
            checked ? "text-foreground/40" : "text-foreground"
          )}
        >
          {offLabel}
        </span>
        <Switch checked={checked} id={id} onCheckedChange={onCheckedChange} />
        <span
          className={cn(
            "font-mono text-sm transition-colors",
            checked ? "text-foreground" : "text-foreground/40"
          )}
        >
          {onLabel}
        </span>
      </div>
      <p className="font-mono text-foreground/55 text-xs">{caption}</p>
    </div>
  );
}

interface TogglesProps {
  grounding: boolean;
  move: boolean;
  onGroundingChange: (next: boolean) => void;
  onMoveChange: (next: boolean) => void;
}

export function Toggles({
  grounding,
  move,
  onGroundingChange,
  onMoveChange,
}: TogglesProps) {
  return (
    <div className="grid gap-6 sm:grid-cols-2">
      <ToggleRow
        caption="off → ask again. on → ask again, with current docs."
        checked={grounding}
        id="plausibility-toggle-grounding"
        label="Grounding"
        offLabel="off"
        onCheckedChange={onGroundingChange}
        onLabel="on"
      />
      <ToggleRow
        caption="re-generate → another plausible answer. re-rank → keep what was said, weigh it."
        checked={move}
        id="plausibility-toggle-move"
        label="Move"
        offLabel="re-generate"
        onCheckedChange={onMoveChange}
        onLabel="re-rank"
      />
    </div>
  );
}

