  const [everMoved, setEverMoved] = useState(false);

  const handleStreamComplete = useCallback(() => {
    setBeat1Complete(true);
  }, []);

  const handleGroundingChange = useCallback((next: boolean) => {
    setGrounding(next);
    if (next) {
      setEverGrounded(true);
    }
  }, []);

  const handleMoveChange = useCallback((next: boolean) => {
    setMove(next);
    if (next) {
      setEverMoved(true);
    }
  }, []);

  const handlePlay = useCallback(() => {
    setBeat1Complete(false);
    setGrounding(false);
    setMove(false);
    setStreamPlays((n) => n + 1);
  }, []);

  const playPressed = streamPlays > 0;
  const showInteractive = beat1Complete;
  const realityRevealed = everGrounded && everMoved;

  return (
    <div className="rounded-2xl border border-border bg-card/40 p-5 shadow-sm sm:p-8">
      <PromptInput
        amended={showInteractive && grounding}
        reducedMotion={reducedMotion}
      />

      <div className="mt-6 min-h-[10rem]">
        {playPressed && !beat1Complete && (
          <StreamingParagraph
            enabled={true}
            key={streamPlays}
            onComplete={handleStreamComplete}
            reducedMotion={reducedMotion}
          />
        )}
        {showInteractive && <AnswerArea grounding={grounding} move={move} />}
        {!playPressed && (
          <p className="font-display text-foreground/30 text-lg leading-8">
            {/* paragraph empty until play */}
          </p>
        )}
      </div>

      {!showInteractive && (
        <div className="mt-6 flex flex-col items-end gap-3">
          {!playPressed && (
            <MetaAside className="text-right">
              About ten seconds. Every other AI demo lies about that.
            </MetaAside>
          )}
          <Button
            aria-label="Play the LLM generation animation"
            disabled={playPressed}
            onClick={handlePlay}
            variant="outline"
          >
            {playPressed ? "Generating…" : "▶ Watch how it generates"}
          </Button>
        </div>
      )}

      {showInteractive && (
        <div className="mt-10 border-border/60 border-t pt-8">
          <MetaAside className="mb-6 max-w-prose" variant="block">
            {HINGE_TO_BEAT_3}
          </MetaAside>
          <Toggles
            grounding={grounding}
            move={move}
            onGroundingChange={handleGroundingChange}
            onMoveChange={handleMoveChange}
          />
          <div className="mt-6 flex justify-end">
            <Button onClick={handlePlay} variant="ghost">
              ↻ Replay generation
            </Button>
          </div>
        </div>
      )}

      {realityRevealed && (
        <div className="fade-in slide-in-from-bottom-2 mt-10 animate-in border-border/60 border-t pt-8 duration-500">
          <MetaAside className="mb-4 max-w-prose" variant="block">
            {HINGE_TO_REALITY}
          </MetaAside>
          <p className="mb-2 font-medium font-mono text-[0.7rem] text-ht-cyan-700 uppercase tracking-[0.2em] dark:text-ht-cyan-300/90">
            Reality
          </p>
          <p className="text-balance text-foreground/85 text-lg leading-8">
            {REALITY_TEXT}
          </p>
        </div>
      )}
    </div>
  );
}

import { OWNED_ANSWER } from "./paragraph-data";

interface DiagnosisChunk {
  id: string;
  kind: "code" | "text";
  text: string;
}

const DIAGNOSIS_CHUNKS: DiagnosisChunk[] = OWNED_ANSWER.diagnosis
  .split(/(`[^`]+`)/g)
  .filter((chunk) => chunk.length > 0)
  .map((chunk, index) => {
    const isCode = chunk.startsWith("`") && chunk.endsWith("`");
    return {
      id: `dx-${index}`,
      kind: isCode ? "code" : "text",
      text: isCode ? chunk.slice(1, -1) : chunk,
    };
  });

export function OwnedAnswer() {
  return (
    <div>
      <blockquote className="font-display text-base text-foreground/55 italic leading-7">
        {OWNED_ANSWER.quotedFromGrounded.text}
        <span className="line-through decoration-2 decoration-red-500/70">
          <span className="sr-only">struck through: </span>
          {OWNED_ANSWER.quotedFromGrounded.strikeThroughClause}
        </span>
      </blockquote>

      <p className="mt-6 font-display font-semibold text-foreground text-xl leading-8">
        {OWNED_ANSWER.callout}
      </p>

      <p className="mt-6 font-display text-foreground/85 text-lg leading-8">
        {DIAGNOSIS_CHUNKS.map((chunk) =>
          chunk.kind === "code" ? (
            <code
              className="rounded bg-foreground/[0.06] px-1 py-0.5 font-mono text-[0.95em] text-foreground/90"
              key={chunk.id}
            >
              {chunk.text}
            </code>
          ) : (
            <span key={chunk.id}>{chunk.text}</span>
          )
        )}
      </p>

      <pre className="mt-6 overflow-x-auto rounded-md border border-border/60 bg-foreground/[0.03] p-4 font-mono text-sm leading-6">
        <code>
          {OWNED_ANSWER.diff.removed.map((line) => (
            <div
              className="text-red-600/85 dark:text-red-400/90"
              key={`r-${line}`}
            >
              <span aria-hidden="true" className="select-none">
                {"- "}
              </span>
              {line}
            </div>
          ))}
          {OWNED_ANSWER.diff.added.map((line) => (
            <div
              className="text-emerald-700/90 dark:text-emerald-400/95"
              key={`a-${line}`}
            >
              <span aria-hidden="true" className="select-none">
                {"+ "}
              </span>
              {line}
            </div>
          ))}
        </code>
      </pre>
    </div>
  );
}

import { cn } from "@repo/design-system/lib/utils";
import { type Token, UNGROUNDED_TOKENS } from "./paragraph-data";

function isCodeToken(token: Token) {
  return token.text.startsWith("`") && token.text.endsWith("`");
}

function renderTokenText(token: Token) {
  if (!isCodeToken(token)) {
    return token.text;
  }
  return (
    <code className="rounded bg-foreground/[0.06] px-1 py-0.5 font-mono text-[0.95em] text-foreground/90">
      {token.text.slice(1, -1)}
    </code>
  );
}

export function UngroundedParagraph() {
  return (
    <p className="font-display text-foreground/85 text-lg leading-8">
      {UNGROUNDED_TOKENS.map((token) => (
        <span
          className={cn(
            "whitespace-pre-wrap",
            token.wrong && "border-red-500/70 border-b-2"
          )}
          key={token.id}
        >
          {renderTokenText(token)}
        </span>
      ))}
    </p>
  );
}

