async () => {
  await new Promise(r => setTimeout(r, 11000));
  const groundingOn = document.querySelector('[aria-label="Grounding"] [data-slot="toggle-group-item"][value="on"], [aria-label="Grounding"] button[value="on"]');
  const moveOn = document.querySelector('[aria-label="Move"] [data-slot="toggle-group-item"][value="on"], [aria-label="Move"] button[value="on"]');
  const groundingOff = document.querySelector('[aria-label="Grounding"] button[value="off"]');
  const moveOff = document.querySelector('[aria-label="Move"] button[value="off"]');
  return {
    foundGroundingOn: !!groundingOn,
    foundMoveOn: !!moveOn,
    foundGroundingOff: !!groundingOff,
    foundMoveOff: !!moveOff,
    groundingOnState: groundingOn?.getAttribute('data-state'),
    moveOnState: moveOn?.getAttribute('data-state')
  };
}

