async () => {
  await new Promise(r => setTimeout(r, 11500));
  // toggle grounding=on
  const groundingItems = document.querySelectorAll('[aria-label="Grounding"] [data-slot="toggle-group-item"]');
  Array.from(groundingItems).find(i => i.textContent.trim() === 'on')?.click();
  await new Promise(r => setTimeout(r, 600));
  // toggle move=re-rank
  const moveItems = document.querySelectorAll('[aria-label="Move"] [data-slot="toggle-group-item"]');
  Array.from(moveItems).find(i => i.textContent.trim() === 're-rank')?.click();
  await new Promise(r => setTimeout(r, 700));
  return 'both probed';
}

